INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (20025, "2022/03/17 15:00:00", 20025004, 2, 190801, 2, 0.0, "カリン", "2030/01/01 14:59:59", "報酬がもらえますよ！\nチェックしてみてください", 4, -416.5, 0.0, 54);
